import argparse

def convert_text(text, case):
    if case == 'upper':
        return text.upper()
    elif case == 'lower':
        return text.lower()
    elif case == 'title':
        return text.title()
    elif case == 'sentence':
        return text.capitalize()
    else:
        return text

def read_file(file_path):
    with open(file_path, 'r') as file:
        return file.read()

